<template>
  <div class="docker-tool">
    <el-card>
      <div slot="header">
        <span>Docker 配置生成器</span>
        <el-button-group class="header-actions">
          <el-button size="small" @click="resetForm">重置</el-button>
        </el-button-group>
      </div>

      <el-row :gutter="20">
        <el-col :span="12">
          <el-card shadow="hover">
            <div slot="header">
              <span>Dockerfile 配置</span>
            </div>
            
            <el-form :model="dockerfileForm" label-width="120px">
              <el-form-item label="基础镜像">
                <el-select v-model="dockerfileForm.baseImage" style="width: 100%">
                  <el-option label="node:16-alpine" value="node:16-alpine" />
                  <el-option label="node:18-alpine" value="node:18-alpine" />
                  <el-option label="node:20-alpine" value="node:20-alpine" />
                  <el-option label="openjdk:8-alpine" value="openjdk:8-alpine" />
                  <el-option label="openjdk:11-alpine" value="openjdk:11-alpine" />
                  <el-option label="openjdk:17-alpine" value="openjdk:17-alpine" />
                  <el-option label="python:3.9-alpine" value="python:3.9-alpine" />
                  <el-option label="python:3.10-alpine" value="python:3.10-alpine" />
                  <el-option label="golang:1.18-alpine" value="golang:1.18-alpine" />
                  <el-option label="golang:1.20-alpine" value="golang:1.20-alpine" />
                </el-select>
              </el-form-item>
              
              <el-form-item label="工作目录">
                <el-input v-model="dockerfileForm.workDir" placeholder="/app" />
              </el-form-item>
              
              <el-form-item label="复制文件">
                <el-checkbox v-model="dockerfileForm.copyPackageJson">复制 package.json</el-checkbox>
              </el-form-item>
              
              <el-form-item label="安装依赖">
                <el-checkbox v-model="dockerfileForm.installDependencies">安装依赖</el-checkbox>
              </el-form-item>
              
              <el-form-item label="构建命令">
                <el-input v-model="dockerfileForm.buildCommand" placeholder="npm run build" />
              </el-form-item>
              
              <el-form-item label="暴露端口">
                <el-input-number v-model="dockerfileForm.port" :min="1" :max="65535" />
              </el-form-item>
              
              <el-form-item label="启动命令">
                <el-input v-model="dockerfileForm.startCommand" placeholder="npm start" />
              </el-form-item>
            </el-form>
          </el-card>
        </el-col>

        <el-col :span="12">
          <el-card shadow="hover">
            <div slot="header">
              <span>docker-compose 配置</span>
            </div>
            
            <el-form :model="dockerComposeForm" label-width="120px">
              <el-form-item label="服务名称">
                <el-input v-model="dockerComposeForm.serviceName" placeholder="app" />
              </el-form-item>
              
              <el-form-item label="容器名称">
                <el-input v-model="dockerComposeForm.containerName" placeholder="my-app" />
              </el-form-item>
              
              <el-form-item label="端口映射">
                <el-input v-model="dockerComposeForm.portMapping" placeholder="3000:3000" />
              </el-form-item>
              
              <el-form-item label="挂载卷">
                <el-checkbox v-model="dockerComposeForm.volumeMount">挂载当前目录</el-checkbox>
              </el-form-item>
              
              <el-form-item label="环境变量">
                <el-checkbox v-model="dockerComposeForm.envFile">使用 .env 文件</el-checkbox>
              </el-form-item>
              
              <el-form-item label="重启策略">
                <el-select v-model="dockerComposeForm.restartPolicy" style="width: 100%">
                  <el-option label="no" value="no" />
                  <el-option label="always" value="always" />
                  <el-option label="on-failure" value="on-failure" />
                  <el-option label="unless-stopped" value="unless-stopped" />
                </el-select>
              </el-form-item>
            </el-form>
          </el-card>
        </el-col>
      </el-row>

      <el-row style="margin-top: 20px">
        <el-col :span="12">
          <el-card shadow="hover">
            <div slot="header">
              <span>Dockerfile 生成结果</span>
              <el-button size="small" @click="copyDockerfile" type="primary">复制</el-button>
            </div>
            <el-input
              type="textarea"
              :rows="15"
              :value="generatedDockerfile"
              readonly
              class="code-area"
            />
          </el-card>
        </el-col>

        <el-col :span="12">
          <el-card shadow="hover">
            <div slot="header">
              <span>docker-compose.yml 生成结果</span>
              <el-button size="small" @click="copyDockerCompose" type="primary">复制</el-button>
            </div>
            <el-input
              type="textarea"
              :rows="15"
              :value="generatedDockerCompose"
              readonly
              class="code-area"
            />
          </el-card>
        </el-col>
      </el-row>
    </el-card>
  </div>
</template>

<script>
export default {
  name: 'DockerTool',
  data() {
    return {
      dockerfileForm: {
        baseImage: 'node:18-alpine',
        workDir: '/app',
        copyPackageJson: true,
        installDependencies: true,
        buildCommand: 'npm run build',
        port: 3000,
        startCommand: 'npm start'
      },
      dockerComposeForm: {
        serviceName: 'app',
        containerName: 'my-app',
        portMapping: '3000:3000',
        volumeMount: true,
        envFile: true,
        restartPolicy: 'unless-stopped'
      }
    }
  },
  computed: {
    generatedDockerfile() {
      const { baseImage, workDir, copyPackageJson, installDependencies, buildCommand, port, startCommand } = this.dockerfileForm
      
      let dockerfile = `FROM ${baseImage}\n`
      dockerfile += `WORKDIR ${workDir}\n\n`
      
      if (copyPackageJson) {
        dockerfile += `COPY package*.json ${workDir}/\n\n`
      }
      
      if (installDependencies) {
        dockerfile += `RUN npm install\n\n`
      }
      
      dockerfile += `COPY . ${workDir}/\n\n`
      
      if (buildCommand) {
        dockerfile += `RUN ${buildCommand}\n\n`
      }
      
      if (port) {
        dockerfile += `EXPOSE ${port}\n\n`
      }
      
      dockerfile += `CMD ["${startCommand}"]`
      
      return dockerfile
    },
    generatedDockerCompose() {
      const { serviceName, containerName, portMapping, volumeMount, envFile, restartPolicy } = this.dockerComposeForm
      
      let compose = `version: '3'\n\nservices:\n`
      compose += `  ${serviceName}:\n`
      compose += `    build: .\n`
      
      if (containerName) {
        compose += `    container_name: ${containerName}\n`
      }
      
      if (portMapping) {
        compose += `    ports:\n`
        compose += `      - "${portMapping}"\n`
      }
      
      if (volumeMount) {
        compose += `    volumes:\n`
        compose += `      - .:${this.dockerfileForm.workDir}\n`
      }
      
      if (envFile) {
        compose += `    env_file:\n`
        compose += `      - .env\n`
      }
      
      if (restartPolicy) {
        compose += `    restart: ${restartPolicy}\n`
      }
      
      return compose
    }
  },
  methods: {
    resetForm() {
      this.dockerfileForm = {
        baseImage: 'node:18-alpine',
        workDir: '/app',
        copyPackageJson: true,
        installDependencies: true,
        buildCommand: 'npm run build',
        port: 3000,
        startCommand: 'npm start'
      }
      this.dockerComposeForm = {
        serviceName: 'app',
        containerName: 'my-app',
        portMapping: '3000:3000',
        volumeMount: true,
        envFile: true,
        restartPolicy: 'unless-stopped'
      }
    },
    copyDockerfile() {
      this.$copyText(this.generatedDockerfile).then(() => {
        this.$message.success('Dockerfile 已复制到剪贴板')
      })
    },
    copyDockerCompose() {
      this.$copyText(this.generatedDockerCompose).then(() => {
        this.$message.success('docker-compose.yml 已复制到剪贴板')
      })
    }
  }
}
</script>

<style lang="scss" scoped>
.docker-tool {
  .header-actions {
    float: right;
  }
  
  .code-area {
    font-family: 'Courier New', monospace;
    font-size: 14px;
    line-height: 1.5;
  }
}
</style>